package com.phalanx.calc;

/**
 * Basic arithmetic helpers — Java testbed mirror of the Python/TS/JS math_ops.
 * The 4 failure patches under ../../../../../../failures/ mutate this file
 * (or tests) to exercise each scorecard cell.
 */
public final class MathOps {

    private MathOps() {
        // utility class
    }

    public static double add(double a, double b) {
        return a + b;
    }

    public static double subtract(double a, double b) {
        return a - b;
    }

    public static double multiply(double a, double b) {
        return a * b;
    }

    public static double divide(double a, double b) {
        if (b == 0) {
            throw new ArithmeticException("cannot divide by zero");
        }
        return a / b;
    }

    public static double percentage(double part, double whole) {
        if (whole == 0) {
            throw new ArithmeticException("cannot compute percentage of zero");
        }
        return (part / whole) * 100;
    }

    public static double average(double[] values) {
        if (values.length == 0) {
            throw new IllegalArgumentException("cannot average an empty list");
        }
        double sum = 0;
        for (double v : values) {
            sum += v;
        }
        return sum / values.length;
    }
}

package com.phalanx.calc;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import org.junit.jupiter.api.Test;

class MathOpsTest {

    @Test
    void addPositives() {
        assertEquals(5.0, MathOps.add(2, 3));
    }

    @Test
    void addNegatives() {
        assertEquals(0.0, MathOps.add(-1, 1));
    }

    @Test
    void addFloats() {
        assertEquals(0.75, MathOps.add(0.5, 0.25));
    }

    @Test
    void subtractPositives() {
        assertEquals(2.0, MathOps.subtract(5, 3));
    }

    @Test
    void subtractNegative() {
        assertEquals(-10.0, MathOps.subtract(0, 10));
    }

    @Test
    void multiplyPositives() {
        assertEquals(6.0, MathOps.multiply(2, 3));
    }

    @Test
    void multiplyNegatives() {
        assertEquals(-5.0, MathOps.multiply(-1, 5));
    }

    @Test
    void multiplyZero() {
        assertEquals(0.0, MathOps.multiply(0, 100));
    }

    @Test
    void divideClean() {
        assertEquals(2.0, MathOps.divide(6, 3));
    }

    @Test
    void divideFractions() {
        assertEquals(0.25, MathOps.divide(1, 4));
    }

    @Test
    void divideByZeroThrows() {
        assertThrows(ArithmeticException.class, () -> MathOps.divide(1, 0));
    }
}

